select kb.id as id, kbt.id as trashId, kb.title as title, ct.sw_id as swId, user.real_name as createUser, kbt.create_time as pubTime, ct.name as ctName from kb_basic_trash kbt left join kb_basic kb on kbt.basic_id = kb.id left join castle_sys_user user on user.id = kbt.user_id left join kb_category ct on kb.category_id = ct.id where kbt.type = 1
and kb.category_id in (
#{kcId}
)
and kb.title like concat('%',#{kbBaseShowDto.title},'%')
and kbt.create_time like concat(#{kbBaseShowDto.fromTime},'%')
order by kbt.create_time desc
limit #{map.offset},#{map.rows}

